"""
mkt-original layer — 2 Corinthians chapters 11–13
Output: data/commentary/mkt-original/2corinthians.json
Run: python3 scripts/zc-original-2corinthians-11-13.py
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    # INTENT: Merge new verse entries without overwriting already-present keys — safe to re-run.
    # CHANGE? If commentary JSON structure changes from {ch:{v:html}}, update this traversal.
    # VERIFY: Re-running the script should produce identical output.
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

NEW = {
  "11": {
    "1": "Bear with me (anechesthe) in a little foolishness (aphrosunē) — the fool's speech (aphrosunē Logos) is a recognized rhetorical genre in Hellenistic literature; Paul adopts it ironically. The present imperative anechesthe (keep on bearing with me) signals that his self-defense has been ongoing and he needs their continued patience.",
    "2": "I feel a divine jealousy (zēlos theou) for you — zēlos can mean both jealousy and zeal; Paul uses the divine genitive to distinguish this from petty jealousy. He presented (hērmosamen, betrothed, from harmozō, to fit together) you as a pure virgin (parthenon hagnēn) to Christ — the betrothal/marriage metaphor frames the relationship between Christ and the church.",
    "3": "But I am afraid that as the serpent deceived Eve by his cunning (panourgia) — panourgia (craftiness, cunning) was a strongly negative term in Greek ethics; the Stoics identified it with the vice opposed to practical wisdom. Your thoughts (noēmata, minds, understanding) may be led astray from a sincere (haplotēs, simplicity, singlemindedness) and pure devotion to Christ.",
    "4": "If someone comes and proclaims another Jesus (allon Iesoun) — the triple another (allos, another; heteron, different; allos again) marks a qualitative difference from the gospel Paul preached. Heteron pneuma (a different Spirit) and heteron euangelion (a different gospel) echo Galatians 1:6-7's warning about perverting the gospel.",
    "6": "Even if I am unskilled (idiōtēs) in speaking — the idiōtēs (layperson, amateur, one without professional training) was the opposite of the trained rhetor in Greco-Roman culture. Paul freely concedes the accusation; but knowledge (gnōsis) is the substance of communication, not stylistic polish.",
    "7": "Or did I commit a sin (hamartian epoiēsa) in humbling myself so that you might be exalted, because I preached God's gospel to you free of charge? — the rhetorical question assumes the answer no. The humiliation/exaltation polarity echoes the Christ-hymn of Philippians 2:6-11: he humbled himself, therefore God exalted him.",
    "8": "I robbed (esylēsa) other churches by accepting support from them in order to serve you — sylao (to rob, plunder) is a strong metaphor; Paul uses the language of forced exaction to describe what was actually voluntary giving by the Macedonians, dramatizing the moral asymmetry between the churches that supported him and the Corinthians who received his service free.",
    "9": "I was not a burden to anyone — katanarkaō (to be burdensome, literally to numb, make torpid) is unusual; the brothers from Macedonia supplied (prosanaplēroō, filled up alongside) what I lacked. Paul deliberately avoided creating the patron-client dependency that would compromise his message.",
    "10": "As the truth of Christ (alētheia Christou) is in me — the oath formula using Christ as the medium of truth-telling; Paul's boasting (kauchēma) about this will not be silenced (phragēsetai) in the regions of Achaia.",
    "11": "And why? Because I do not love you? God knows I do! — the rhetorical question and immediate divine-appeal answer is a diatribe technique. The appeal to divine knowledge (ho theos oiden) functions as an oath warranty.",
    "12": "What I am doing I will continue to do, in order to undercut (ekkopsō, cut off, eliminate) those who want an opportunity to be regarded as our equals — Paul's continuing practice of free preaching removes the basis on which the intruders could claim to operate on the same level as Paul.",
    "13": "For such men are false apostles (pseudapostoloi), deceitful workers (ergatai dolioi) — the compound pseudapostoloi (false apostles) appears only here in the NT; it parallels pseudoprophētai (false prophets) and pseudodidaskaloi (false teachers). Disguising (metaschēmatizomenoi, transforming the shape of) themselves as apostles of Christ.",
    "14": "And no wonder, for Satan himself disguises himself (metaschēmatizetai) as an angel of light (angelos phōtos) — the present middle of metaschēmatizō (to change the outward form); the verbal repetition from v.13 identifies the intruders' disguise as satanic mimicry. Angel of light is a dramatic contrast with Satan's true nature.",
    "15": "So it is no surprise if his servants also disguise themselves as servants of righteousness (dikaiosynēs) — the servants (diakonoi) of righteousness is their self-presentation; Paul has already identified himself and his co-workers as servants/diakonoi in multiple senses (3:6; 6:4; 11:23). Their end (to telos) will correspond to their works — eschatological justice.",
    "16": "Let no one think me foolish (aphrona); but even if you do, accept me as a fool, so that I too may boast a little — the Stoic sage could not be a fool; the Cynic philosopher embraced the role of the social outsider-critic. Paul appropriates both as ironic self-positioning.",
    "17": "What I am saying with this boastful confidence (hypostasei) I say not as the Lord would but as a fool — hypostasis (standing, substance, confidence) — Paul uses this word for the foundations of faith in Hebrews 11:1. Here it describes the boastful confidence he is about to display, which he explicitly marks as not in the Lord's pattern.",
    "18": "Since many boast according to the flesh (kata sarka), I too will boast — the boasting kata sarka (according to worldly standards) is precisely what Paul argued against in 1 Corinthians 1-3. He enters the game to show that he beats the intruders at their own game, then exposes the game itself as meaningless.",
    "19": "For you gladly bear with (anechesthe) fools, being wise (phronimoi) yourselves! — the irony: the Corinthians pride themselves on wisdom (sophia) but are exposed as those who bear with fools — which makes them fools themselves (Prov 26:4-5: answer a fool according to his folly).",
    "20": "For you bear it if someone enslaves you (katadouloī), devours you (katesthiō), takes advantage of you (lambanei), puts on airs (epairetai), or strikes you in the face — the five verbs of exploitation culminate in the physical: strikes you in the face (ei tis hymas eis prosōpon derei). The progression from economic exploitation to physical violence maps the anatomy of false apostolic authority.",
    "21": "To my shame, I must say, we were too weak for that! — the cutting irony: Paul confesses his shameful weakness was his refusal to exploit the congregation. Whatever anyone else dares to boast of — I am speaking as a fool — I also dare to boast.",
    "22": "Are they Hebrews (Hebraioi)? So am I. Are they Israelites (Israelitai)? So am I. Are they offspring of Abraham (sperma Abraam)? So am I — the three terms represent ethnic identity (Hebrews = Hebrew-speaking Jews), covenant membership (Israelites = belonging to Israel), and messianic lineage (seed of Abraham = heirs of the promise). Paul matches each credential.",
    "23": "Are they servants (diakonoi) of Christ? I am a better one — I am talking like a madman (paraphronōn lalō) — the parenthetical disclaimer intensifies before the peristasis catalogue begins. The suffering catalogue (peristasis catalogue) that follows was a recognized form in Hellenistic moral philosophy for demonstrating the true sage's virtue through endurance.",
    "24": "Five times I received at the hands of the Jews the forty lashes less one — the synagogue discipline of thirty-nine stripes (Deut 25:2-3 capped at forty; practice reduced to thirty-nine to avoid accidental exceeding). This is not recorded in Acts; Paul's letters preserve historical data Acts omits.",
    "25": "Three times I was beaten with rods (rhabdois), once I was stoned (elithasthēn), three times I was shipwrecked (enauagēsa) — the rhabdos-beating was Roman civic punishment (Acts 16:22 at Philippi). The stoning is the Lystra incident (Acts 14:19). The three shipwrecks pre-date the Acts 27 shipwreck that Luke describes.",
    "26": "On frequent journeys, in danger (kindynois) from rivers, danger from robbers — the eight-fold danger list (rivers, robbers, my own people, Gentiles, city, wilderness, sea, false brothers) is structured as a comprehensive catalogue of every threat environment.",
    "27": "In toil and hardship, through many a sleepless night, in hunger and thirst, often without food, in cold and exposure (gymnōtēti, nakedness) — the catalogue shifts from external dangers to physical privations. Gymnōtēs (nakedness, inadequate clothing) reflects actual material destitution, not metaphor.",
    "28": "And, apart from other things, there is the daily pressure on me of my anxiety (merimna) for all the churches — merimna (anxious concern, care) is the word Jesus used for the anxious care about daily necessities (Matt 6:25-34). Paul redirects it: his anxiety is pastoral, not material.",
    "29": "Who is weak (asthenei), and I am not weak? Who is made to fall (skandalizetai), and I am not indignant (ouk pyroō, not on fire)? — the two rhetorical questions describe Paul's pastoral identification with the congregation's vulnerabilities. Pyroō (to burn, be inflamed) is used for passion and indignation.",
    "30": "If I must boast, I will boast of the things that show my weakness (astheneia) — the inversion of the boast-genre: the conventional peristasis catalogue demonstrated strength through endurance; Paul's catalogue concludes by claiming weakness as the proper content of apostolic boasting.",
    "31": "The God and Father of the Lord Jesus, he who is blessed forever, knows that I am not lying — a solemn oath formula at the transition from the general catalogue to the specific Damascus escape incident. The divine knowledge (oiden) serves as the ultimate truth-warrant.",
    "32": "At Damascus, the governor (ho ethnarchēs) under King Aretas guarded (ephroureito) the city of Damascus in order to seize (piasai) me — ethnarchēs was an administrative title for the governor of an ethnic community within a larger political structure. The historical detail is corroborated by Nabataean royal history.",
    "33": "I was let down (echalasthēn, was lowered) in a basket (en sargani, in a woven basket) through a window in the wall and escaped (exephygon, fled out from) his hands — the aorist passives describe the events from Paul's perspective as things done to/for him. The basket (sargane) was a large wicker or rope basket used for cargo.",
  },
  "12": {
    "1": "I must go on boasting (kauchasthai dei) — the dei (must, it is necessary) frames boasting as a compulsory rhetorical act, not voluntary self-promotion. Though there is nothing to be gained by it, I will go on to visions and revelations (optasias kai apokalypseis) of the Lord.",
    "2": "I know a man in Christ (anthrōpon en Christō) who fourteen years ago was caught up (harpagenta, snatched up) to the third heaven — the distancing in the third person (a man in Christ rather than I myself) is Paul's way of boasting while maintaining the posture of the one who will only boast in weakness. Harpazō (snatch up) is used for the violent divine seizure of Elijah (LXX 2 Kgs 2:11) and the eschatological rapture (1 Thess 4:17).",
    "3": "And I know that this man — whether in the body or out of the body I do not know, God knows — the double disclaimer (vv.2 and 3) maintains epistemological humility about the mode of the vision while affirming its reality.",
    "4": "Was caught up into paradise (eis ton paradeison) — paradeisos (paradise, from Persian pairidaeza, walled garden) was used in the LXX for the garden of Eden (Gen 2:8) and in Jewish apocalyptic for the heavenly garden where the righteous await resurrection (1 Enoch 60:8; 4 Ezra 7:36). He heard things that cannot be told (arrhēta rhēmata), which man is not permitted to utter.",
    "5": "On behalf of this man I will boast, but on my own behalf I will not boast, except of my weaknesses — the grammatical distinction between the heavenly-vision man (third person) and the boasting-in-weakness Paul (first person) is maintained throughout. The split is rhetorical and reveals Paul's discomfort with mystical self-disclosure.",
    "6": "Though if I wish to boast, I would not be a fool (aphrōn), for I would be speaking the truth — unlike the conventional fool's-speech disclaimer (I speak as a fool), here Paul notes that the visionary boast would actually be true; his restraint is therefore strategic, not epistemic.",
    "7": "To keep me from being too elated (hyperairōmai, lifted up, exalted beyond measure) by the surpassing greatness (hyperbolē) of the revelations, a thorn (skolops) was given me in the flesh — skolops means a stake or thorn; medical interpreters have proposed epilepsy, eye disease, or malarial fever. A messenger (angelos) of Satan to harass me (hina me kolaphizē, to strike with the fist, beat) — the same verb used for striking Jesus in the Passion (Matt 26:67).",
    "8": "Three times I pleaded (parekalesa) with the Lord about this, that it should leave me — parekaleo (beg, entreat) is the same root as paraklēsis (encouragement, comfort) that opens the letter (1:3-7). Paul's prayer for removal of the thorn is the inverse of his own teaching: the God of all paraklēsis comforts in all affliction.",
    "10": "For the sake of Christ, then, I am content (eudokō, I take pleasure, am well pleased) with weaknesses, insults (hybresin), hardships (anankais, necessities, straits), persecutions (diōgmois), and calamities (stenochoriais, tight places, distresses) — the five nouns form a compressed version of the peristasis catalogue from chapter 11. For when I am weak (astheneō), then I am strong (dynatos).",
    "11": "I have been a fool! You forced me to it (hymeis me ēnagkasate) — the aorist indicates a completed action: the Corinthians' failure to commend Paul is what required the fool's speech. For I ought to have been commended by you, since I was not at all inferior (hysterēsa, lacking, falling short) to these super-apostles (tōn hyperulian apostolōn), even though I am nothing.",
    "12": "The signs of a true apostle were performed among you with utmost patience (en pasē hypomonē) — hypomonē (patient endurance) is not passive resignation but active perseverance. Signs and wonders (sēmeiois kai terasin) and mighty works (dynamesi) — the three-term formula for miraculous attestation echoes Deuteronomy 34:11.",
    "13": "For in what were you less favored than the rest of the churches, except that I myself did not burden you? — the question is designed to sting: the only way the Corinthians were treated less well was that Paul refused to take their money. Forgive me this wrong! (charissasthe moi tēn adikian tautēn) — the mock apology is barbed irony.",
    "14": "Here for the third time I am ready to come to you — the announcement of the third visit frames everything from 12:14 to 13:10. And I will not be a burden (ou katanarkanō), for I seek not what is yours but you (ou ta hyma alla hymas) — the distinction between possessing the community's goods and possessing the community itself is the key to Paul's pastoral ethic.",
    "15": "I will most gladly spend (dapanēsō) and be spent (ekdapanēthēsomai) for your souls — the intensification from spending money to spending the self. The double compound dapanēsō/ekdapanēthēsomai (spend/spend out completely) maps the logic of apostolic self-giving: first resources, then the person.",
    "16": "But granting that I myself did not burden you, I was crafty (hyparchōn panourgos, being a scoundrel) — panourgia (craftiness) appeared in 11:3 for the serpent's cunning; now the Corinthians apparently use it against Paul. He quotes their accusation ironically: yes, and caught you by deceit (dolō hymas elabon).",
    "17": "Did I take advantage of you through any of those whom I sent to you? — the question tests the consistency of Paul's practice: if he was crafty, his agents should show the same craftiness. The logic works in reverse — if Titus and the others acted with integrity, the accusation of Paul's craftiness collapses.",
    "18": "I urged (parekalesa) Titus to go and sent the brother with him — the parallel construction (Titus's integrity = Paul's integrity) is the argument from consistency of character. Did Titus take advantage of you? Did we not act in the same spirit? Did we not take the same steps?",
    "19": "Have you been thinking all along that we have been defending (apologoumetha) ourselves to you? — the sudden shift: the entire letter is not a legal defense before the Corinthians but speech before God in Christ. It is all for your upbuilding (oikodomē), beloved.",
    "20": "For I fear (phoboumai) that perhaps when I come I may find you not as I wish — the list of vices: quarreling (eris), jealousy (zēlos), anger (thymos), selfishness (eritheiai), slander (katalalia), gossip (psithyrismos), arrogance (physiōseis), and disorder (akatastasiai) — the catalogue maps the fractures in the Corinthian community.",
    "21": "And I may have to mourn (penthēsō) over many of those who sinned earlier and have not repented of the impurity (akatharsia), sexual immorality (porneia), and sensuality (aselgeia) they have practiced — the three nouns describe the specific sins of the minority Paul fears he will find unrepentant at his third visit.",
  },
  "13": {
    "1": "This is the third time (tritēn tautēn) I am coming to you — every charge must be established by the evidence of two or three witnesses (Deut 19:15) — Paul applies the Mosaic legal standard (stoma dyoin martyrōn kai triōn stathēsetai pan rhēma) to his pattern of visits: the three visits function as the three-witness testimony.",
    "2": "I warned those who sinned before and all the others, and I warn them now while absent — the double warning (past/present) mirrors the legal requirement for formal warning before executing judgment. If I come again I will not spare them (ou pheisomai) — the language of judicial severity.",
    "3": "Since you seek proof (dokimēn, a test, proof of genuineness) that Christ is speaking in me — dokimē (proof through testing) is Paul's word for authenticated character (2:9; 8:2; 9:13). He who is not weak toward you (eis hymas) but is powerful (dynatos) in you.",
    "4": "For he was crucified in weakness (ex astheneias), but lives by the power of God (ek dynameōs theou) — the cross/resurrection antithesis that runs through 2 Corinthians: weakness is the mode of crucifixion; power is the mode of resurrection. For we also are weak in him, but in dealing with you we will live with him by the power of God.",
    "5": "Examine yourselves (heautous peirazete), to see whether you are in the faith — test yourselves (heautous dokimazete) — the twin imperatives use both peirazō (test, tempt) and dokimazō (assay, evaluate); the distinction is that dokimazō implies the expectation of approval. Or do you not realize this about yourselves, that Jesus Christ is in you (en hymin)? — unless indeed you fail to meet the test (adokimoi este).",
    "6": "I hope you will find out that we have not failed the test (hoti hēmeis ouk esmen adokimoi) — the word adokimos (failing the test, disqualified) appeared in 1 Cor 9:27 for Paul's fear of his own disqualification; here he applies it to the Corinthians' evaluation of him.",
    "7": "But we pray to God that you may not do wrong (kakōn mē poiēsai) — not that we may appear to have met the test (hina hēmeis dokimoi phanōmen), but that you may do what is right (kalon poiēte), though we may seem to have failed — the selflessness of the pastoral prayer: Paul would rather appear adokimos himself than have the Corinthians fail morally.",
    "8": "For we cannot do anything against the truth (kata tēs alētheias), but only for the truth (hyper tēs alētheias) — the epistemological constraint: Paul's apostolic authority is bounded by truth itself; he cannot act against it regardless of personal advantage.",
    "9": "For we are glad when we are weak and you are strong (dynatos ēte) — the inversion of conventional success metrics: Paul rejoices in his own weakness when it accompanies the congregation's strength. Your restoration (katartisis, mending, fitting together — the same root as katartizō in v.11) is what we pray for.",
    "10": "For this reason I write these things while I am away from you, that when I come I may not have to be severe (apotomōs, sharply, with cutting severity) — apotomōs (sharply, from apotemnō, to cut off) was used for abrupt/harsh action. In my use of the authority (exousia) the Lord has given me for building up (oikodomēn) and not for tearing down (kathairesis) — the building/tearing-down polarity echoes Jeremiah 1:10.",
    "11": "Finally, brothers, rejoice (chairete). Aim for restoration (katartizesthe, be restored, be mended). Comfort one another (parakaleisthe). Agree with one another (to auto phroneite). Live in peace (eirēneuete) — the five closing imperatives: joy, restoration, mutual comfort, like-mindedness, peace. And the God of love and peace will be with you.",
    "12": "Greet one another with a holy kiss (philēmati hagiō) — the holy kiss appears in all four Pauline letter-closing greetings where it occurs (Rom 16:16; 1 Cor 16:20; 1 Thess 5:26; here). All the saints greet you.",
    "13": "All the saints greet you — the expansion of the greeting to include all the saints situates the letter in the broader fellowship of the universal church; the local letter is a communication within a network of interconnected communities.",
    "14": "The grace (charis) of the Lord Jesus Christ and the love (agapē) of God and the fellowship (koinōnia) of the Holy Spirit be with you all — the most explicitly trinitarian benediction in the Pauline corpus. Three divine persons are named with three distinct attributes: Christ's grace (the gift freely given through the cross), God's love (the eternal source of the gift), and the Spirit's koinōnia (the shared participation that binds the community to God and to one another).",
  }
}

if __name__ == '__main__':
    existing = load_comm('mkt-original', '2corinthians')
    merge_comm(existing, NEW)
    save_comm('mkt-original', '2corinthians', existing)
    for ch in ['11', '12', '13']:
        print(f'  ch {ch}: {len(existing.get(ch, {}))} verses')
